return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2026-03-27 09:00:36+0000','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11) ? 0 : ((n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 12 || n % 100 > 14)) ? 1 : 2);','project-id-version'=>'Plugins - Translate Multilingual sites &#8211; TranslatePress - Stable (latest release)','language'=>'hr','messages'=>['Invalid language code'=>'Nevažeći jezični kod','Domain is reachable!'=>'Domena je dostupna!','Domain returned HTTP status %d.'=>'Domena vraća HTTP status %d.','Could not reach domain: %s'=>'Nije se moglo doći do domene: %s','Invalid domain format.'=>'Nevažeći format domene.','Please enter a domain.'=>'Molimo unesite domenu.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Različita domena po jeziku: Jezična domena ne može biti ista kao glavni URL stranice. Prekidač je onemogućen za domenu podudaranja.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Različita domena po jeziku: Ista domena ne može se dodijeliti za više jezika. Izmjenjivač je onemogućen za duplicirane domene.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Različita domena po jeziku: Domena je potrebna kada je mapiranje domena omogućeno. Izmjenjivač je onemogućen za jezike s praznim domenama.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Napomena: Ova opcija je onemogućena kada je dodatak Različita domena po jeziku aktivan.','This domain is already assigned to another language.'=>'Ta domena je već dodijeljena drugom jeziku.','DNS check failed. Please verify your domain configuration.'=>'DNS provjera nije uspjela. Molimo provjerite konfiguraciju svoje domene.','DNS is correctly configured!'=>'DNS je ispravno konfiguriran!','Checking DNS...'=>'Provjeravam DNS...','Check DNS'=>'Provjeri DNS','Prefill with current domain'=>'Prethodno popuni s trenutnom domenom','https://example.com'=>'https://example.com','Map this language to a different domain or sub-domain.'=>'Mapirajte ovaj jezik na drugu domenu ili poddomenu.','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Provjerite jesu li vaše domene registrirane, usmjerene na vaš server i imate konfigurirane SSL certifikate.','Before enabling:'=>'Prije omogućavanja:','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Dodijelite različite domene ili poddomene svakom jeziku. Kada posjetitelji pristupe tim domenama, TranslatePress učitava odgovarajući jezični prijevod izravno bez preusmjeravanja.','View Docs'=>'Prikaz dokumenata','unknown'=>'nepoznato','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Povežite zasebne domene ili poddomene sa svakom od vaših prevedenih verzija. Ojačajte lokalni identitet svog brenda i poboljšajte SEO performanse za svaki jezik koji podržavate.','Different Domain per Language'=>'Različita domena po jeziku','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress proaktivno skenira i sprema stringove u bazi podataka kada korisnici pristupaju prevedenim stranicama. <br>Ova postavka onemogućava ovu funkcionalnost i dopušta prijevod i spremanje nizova samo kada su unutar uređivača prijevoda. <br>Također onemogućava strojno prevođenje izvan uređivača prijevoda, dajući vam bolju kontrolu nad trošenjem znakova, tako da prevode samo stranice koje posjetite u uređivaču prijevoda.','%d day ago'=>'%d dan prije' . "\0" . '%d dana prije' . "\0" . '%d dana prije','%d hour ago'=>'%d sat prije' . "\0" . '%d sata prije' . "\0" . '%d sati prije','Just now'=>'Upravo sad','Unable to parse feed'=>'Nije moguće raščlaniti sadržaj','Empty feed response'=>'Odziv praznog sadržaja','Close'=>'Zatvori','Ask the community'=>'Pitaj zajednicu','Toggle support chat'=>'Prebaci na chat za podršku','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Uključuje što ste pokušali, što ste očekivali i što se dogodilo. Snimke zaslona pomažu!','Tip for faster help:'=>'Savjet za bržu pomoć:','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Zatražite pomoć izravno od developera plugina, predložite poboljšanja ili podijelite svoje povratne informacije!','Have a question?'=>'Imate pitanje?','by'=>'od','View All Topics'=>'Pogledajte sve teme','Ask a Question'=>'Postavite pitanje','Unable to load forum posts'=>'Nije moguće učitati forumske objave','Loading...'=>'Učitavanje ...','Recent community discussions'=>'Nedavne rasprave u zajednici','Need Help?'=>'Trebate pomoć?','Get More AI Words (%d left)'=>'Nabavite više AI riječi (%d ostalo)','Get a Free AI License'=>'Nabavite besplatnu AI licencu','Add a New Language'=>'Dodaj novi jezik','Search original and translated strings containing typed keywords while also matching selected filters. Place string in quotes for exact match: "string"'=>'Pretražujte izvorne i prevedene nizove koji sadrže tipizirane ključne riječi, dok istovremeno usklađujete odabrane filtre. Stavite string u navodnike za točno podudaranje: "string"','Select the language your content is written in.'=>'Odaberite jezik na kojem je vaš sadržaj napisan.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Ako imate instaliran samo besplatni dodatak, ali ste dodali plaćenu licencu, molimo instalirajte plaćeni dodatak sa svog TranslatePress računa.','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Ako imate instaliran samo besplatni dodatak, ali ste dodali plaćenu licencu, molimo instalirajte plaćeni dodatak sa svog TranslatePress računa.','Available languages'=>'Dostupni jezici','WordPress Translation Plugin'=>'WordPress dodatak za prevođenje','Change language'=>'Promijeni jezik','Change language to %s'=>'Promijenite jezik u %s','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Čarobnjak za postavljanje omogućava vam brzo postavljanje TranslatePressa. Možete ga pokrenuti u bilo kojem trenutku.','Re-run Setup Wizard'=>'Ponovno pokrenite čarobnjak za postavljanje','It takes less than a minute.'=>'Potrebno je manje od minute.','Quick guided setup to configure TranslatePress in no time!'=>'Brzo vođeno postavljanje za konfiguriranje TranslatePressa u tren oka!','Welcome to TranslatePress'=>'Dobrodošli u TranslatePress','Transparent'=>'Transparentno','Transparent Template'=>'Prozirni predložak','Border'=>'Rub','Border Template'=>'Predložak ruba','Dark Template'=>'Tamni predložak','Default Template'=>'Zadani predložak','You can customize the design later'=>'Dizajn možete prilagoditi kasnije','Apply a Template'=>'Primjeni predlžak','Switcher Location'=>'Izmjenjivač jezika','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Prikazuje mali padajući izbornik jezika na vašoj web stranici, u kutu po vašem izboru.','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Odaberi